<template>
  <div class="calendar-container">
    <div class="fixed-header">
      <div class="header-top">
        <h1 class="month-title">{{ currentMonthTitle }}</h1>
        <div class="header-bottom">
          <label for="startDay">시작 요일:</label>
          <select id="startDay" v-model="startDayIndex">
            <option value="0">일요일</option>
            <option value="1">월요일</option>
          </select>
          <button @click="requestNotificationPermission" class="noti-permission-btn" title="알림 설정">🔔</button>
        </div>
      </div>
    </div>
    <div class="weekdays">
      <span
        v-for="day in reorderedWeekdays"
        :key="day"
        :class="{'sunday': day === '일', 'saturday': day === '토'}"
      >
        {{ day }}
      </span>
    </div>
    <div class="days">
      <span
        v-for="day in daysInCurrentMonth"
        :key="day.key"
        :class="{
          'day': true,
          'padded': day.padded,
          'today': day.isToday,
          'my-duty': getDutyName(day.dateKey) && getDutyName(day.dateKey).isMe 
        }"
        @click="handleDayClick(day)"
      >
        {{ day.number }}
        
        <div v-if="getDutyName(day.dateKey)" class="duty-name">
          {{ getDutyName(day.dateKey).name }}
        </div>
      </span>
    </div>

    <!-- <div class="nav-buttons-container">
      <button @click="prevMonth" class="nav-button prev-button">‹</button>
      <button @click="nextMonth" class="nav-button next-button">›</button>
    </div> -->

    <div v-if="updateExists" class="update-notification">
      <p>새로운 버전 발견! 업데이트하시겠습니까?</p>
      <button @click="refreshApp">업데이트</button>
    </div>

    <div v-if="showPasswordModal" class="modal-overlay">
      <div class="modal-content">
        <h3>비밀번호 확인</h3>
        <p>당직 정보를 수정/입력하려면 비밀번호를 입력하세요.</p>
        <input type="password" v-model="passwordInput" @keyup.enter="validatePassword" placeholder="비밀번호" autofocus>
        <div class="modal-buttons">
          <button @click="validatePassword" class="modal-confirm">확인</button>
          <button @click="cancelPassword" class="modal-cancel">취소</button>
        </div>
        <p v-if="passwordMessage" class="error-message">{{ passwordMessage }}</p>
      </div>
    </div>
    
    <div v-if="showEditForm" class="edit-form-container">
      <h2>{{ formDocId ? '당직 정보 수정' : '새 당직 정보 입력' }} ({{ currentEditingDate }})</h2>
      
      <div class="form-grid">
        <label for="category">Category:</label>
        <input id="category" type="text" v-model="formEntry.category">

        <label for="holidayYn">Holiday (Y/N):</label>
        <select id="holidayYn" v-model="formEntry.holidayYn">
          <option value="Y">Y</option>
          <option value="N">N</option>
        </select>
        
        <label for="meYn">Me (Y/N):</label>
        <select id="meYn" v-model="formEntry.meYn">
          <option value="Y">Y</option>
          <option value="N">N</option>
        </select>
        
        <label for="name">Name:</label>
        <input id="name" type="text" v-model="formEntry.name">
        
        <label for="sendNoti">알림 여부:</label>
        <input id="sendNoti" type="checkbox" v-model="formEntry.sendNotification" style="width: 20px; height: 20px;">

        <div class="form-buttons">
          <button @click="saveDuty" class="save-button">저장</button>
          <button @click="closeForm" class="cancel-button">취소</button>
          <button @click="goToSetting" class="setting-button">설정</button>
        </div>
      </div>
      <p v-if="formMessage" :class="{'error-message': formError, 'success-message': !formError}">
        {{ formMessage }}
      </p>
    </div>
  </div>
</template>

<script>
export default {
  name: 'HelloWorld',
  props: {
    dutyData: {
      type: Array,
      default: () => []
    },
    saveDutyEntry: {
      type: Function,
      required: true
    },
    checkPassword: {
      type: Function,
      required: true
    }
  },
  data() {
    return {
      weekdays: ['일', '월', '화', '수', '목', '금', '토'],
      currentDate: new Date(),
      startDayIndex: parseInt(localStorage.getItem('startDayIndex')) || 0,
      updateExists: false,
      registration: null,

      lastTaps: [], 
      editingDay: null, 
      currentEditingDate: '',
      formDocId: null,

      showPasswordModal: false,
      passwordInput: '',
      passwordMessage: '',

      showEditForm: false,
      formEntry: {
        category: '당직',
        date: '',
        holidayYn: 'N',
        meYn: 'N',
        name: '',
        sendNotification: true
      },
      formMessage: '',
      formError: false,
    };
  },
  computed: {
    currentMonthTitle() {
      const year = this.currentDate.getFullYear();
      const month = this.currentDate.getMonth();
      return `${year}년 ${month + 1}월`;
    },
    reorderedWeekdays() {
      const days = [...this.weekdays];
      for (let i = 0; i < this.startDayIndex; i++) {
        days.push(days.shift());
      }
      return days;
    },
    daysInCurrentMonth() {
      const year = this.currentDate.getFullYear();
      const month = this.currentDate.getMonth();
      const today = new Date();
      const days = [];
      
      const firstDayOfMonth = new Date(year, month, 1).getDay();
      const firstDayWithOffset = (firstDayOfMonth - this.startDayIndex + 7) % 7;
      
      // 2. 지난 달 날짜 계산 및 채우기
      const prevDate = new Date(year, month, 0); 
      const daysInPrevMonth = prevDate.getDate();
      const prevMonthYear = prevDate.getFullYear();
      const prevMonth = prevDate.getMonth() + 1; 
      
      for (let i = 0; i < firstDayWithOffset; i++) {
        const dayNumber = daysInPrevMonth - firstDayWithOffset + 1 + i;
        const dateKey = this.formatDate(prevMonthYear, prevMonth, dayNumber);
        days.push({ 
          key: `prev-${dateKey}`, 
          number: dayNumber, 
          padded: true,
          isToday: false,
          dateKey: dateKey
        });
      }

      // 3. 현재 달 날짜 채우기
      const daysInMonth = new Date(year, month + 1, 0).getDate();
      const currentMonth = month + 1;
      
      for (let j = 1; j <= daysInMonth; j++) {
        const currentDate = new Date(year, month, j);
        const isToday = currentDate.toDateString() === today.toDateString();
        const dateKey = this.formatDate(year, currentMonth, j);
        days.push({ 
          key: `current-${dateKey}`, 
          number: j, 
          padded: false, 
          isToday, 
          dateKey: dateKey
        });
      }
      
      // 4. 다음 달 날짜 계산 및 채우기 (총 42개 칸을 목표로)
      const nextDate = new Date(year, month + 1, 1);
      const nextMonthYear = nextDate.getFullYear();
      const nextMonth = nextDate.getMonth() + 1;
      let nextDayNumber = 1;

      while (days.length < 42 && days.length % 7 !== 0) {
        const dateKey = this.formatDate(nextMonthYear, nextMonth, nextDayNumber);
        days.push({ 
          key: `next-${dateKey}`, 
          number: nextDayNumber, 
          padded: true,
          isToday: false,
          dateKey: dateKey
        });
        nextDayNumber++;
      }
      
      return days;
    }
  },
  watch: {
    startDayIndex(newVal) {
      localStorage.setItem('startDayIndex', newVal);
    }
  },
  created() {
    document.addEventListener('swUpdated', this.showUpdatePrompt, { once: true });
  },
  methods: {
    async requestNotificationPermission() {
      try {
        // 브라우저 기본 권한 요청
        const permission = await Notification.requestPermission();
        
        if (permission === 'granted') {
          alert('알림 권한이 허용되었습니다! 이제 당직 업데이트 알림을 받으실 수 있습니다.');
          // 권한 허용 시 페이지를 새로고침하여 App.vue의 토큰 저장 로직을 다시 실행시킵니다.
          window.location.reload(); 
        } else if (permission === 'denied') {
          alert('알림 권한이 거부되었습니다. 설정에서 알림을 허용해주세요.');
        }
      } catch (error) {
        console.error('알림 권한 요청 중 오류:', error);
        alert('이 브라우저에서는 알림 기능을 지원하지 않거나 오류가 발생했습니다.');
      }
    },
    // 기존의 saveDuty 함수를 모두 지우고 이 하나만 딱 넣으세요.
    async saveDuty() {
      this.formMessage = '저장 중...';
      this.formError = false;

      // 부모(App.vue)의 saveDutyEntry 호출
      const isSuccess = await this.saveDutyEntry(this.formEntry, this.formDocId);

      if (isSuccess) {
        this.formMessage = '성공적으로 저장되었습니다.';
        setTimeout(() => {
          this.closeForm();
        }, 500);
      } else {
        this.formMessage = '저장에 실패했습니다.';
        this.formError = true;
      }
    },
    formatDate(year, month, day) {
      const yearFormatted = String(year).slice(-2);
      const monthFormatted = String(month).padStart(2, '0');
      const dayFormatted = String(day).padStart(2, '0');
      return `${yearFormatted}${monthFormatted}${dayFormatted}`;
    },
    goToSetting() {
      this.closeForm(); // 폼을 닫고
      this.$emit('open-setting'); // 부모(App.vue)에게 설정 페이지 열라고 신호 보냄
    },
    getDutyName(dateKey) {
      if (!dateKey || !this.dutyData) return null;
      
      const dutyPerson = this.dutyData.find(person => 
        person.date === dateKey && person.category === '당직'
      );
      
      if (dutyPerson) {
          return { 
            name: dutyPerson.name, 
            isMe: dutyPerson.meYn === 'Y', 
            docId: dutyPerson.id,
            fullEntry: dutyPerson
          };
      }
      return null;
    },

    handleDayClick(day) {
      if (day.padded) return;

      const now = Date.now();
      const dateKey = day.dateKey;
      
      this.lastTaps = this.lastTaps.filter(time => now - time < 500); 
      this.lastTaps.push(now);

      if (this.lastTaps.length === 3) {
        this.editingDay = day.number;
        this.currentEditingDate = dateKey;
        this.showPasswordModal = true;
        this.passwordInput = '';
        this.passwordMessage = '';
        this.lastTaps = []; 
      }
    },

    async validatePassword() {
      this.passwordMessage = '확인 중...';
      const result = await this.checkPassword(this.passwordInput);
      
      if (result.success) {
        this.passwordMessage = '';
        this.showPasswordModal = false;
        this.openEditForm();
      } else {
        this.passwordMessage = result.message || "비밀번호가 올바르지 않습니다.";
      }
    },
    
    cancelPassword() {
      this.showPasswordModal = false;
      this.passwordInput = '';
      this.passwordMessage = '';
    },

    openEditForm() {
      const dutyEntry = this.getDutyName(this.currentEditingDate); 
      
      this.formEntry.date = this.currentEditingDate; 
      this.formMessage = '';
      this.formError = false;

      if (dutyEntry && dutyEntry.fullEntry) {
        const entry = dutyEntry.fullEntry;
        this.formDocId = entry.id;
        this.formEntry.category = entry.category;
        this.formEntry.holidayYn = entry.holidayYn;
        this.formEntry.meYn = entry.meYn;
        this.formEntry.name = entry.name;
      } else {
        this.formDocId = null;
        this.formEntry.category = '당직'; 
        this.formEntry.holidayYn = 'N'; 
        this.formEntry.meYn = 'N'; 
        this.formEntry.name = ''; 
      }
      this.formEntry.sendNotification = true;
      this.showEditForm = true;
    },


    closeForm() {
      this.showEditForm = false;
      this.editingDay = null;
      this.currentEditingDate = '';
      this.formDocId = null;
      this.formMessage = '';
      this.formError = false;
      this.formEntry = { category: '당직', date: '', holidayYn: 'N', meYn: 'N', name: '', sendNotification: true };
    },

    prevMonth() {
      this.currentDate = new Date(this.currentDate.getFullYear(), this.currentDate.getMonth() - 1, 1);
      this.closeForm();
    },
    nextMonth() {
      this.currentDate = new Date(this.currentDate.getFullYear(), this.currentDate.getMonth() + 1, 1);
      this.closeForm();
    },
    showUpdatePrompt (event) {
      this.registration = event.detail;
      this.updateExists = true;
    },
    refreshApp () {
      this.updateExists = false;
      if (this.registration && this.registration.waiting) {
        this.registration.waiting.postMessage({ type: 'SKIP_WAITING' });
      }
      window.location.reload();
    }
  }
};
</script>

