<template>
  <div class="sub-page-overlay">
    <div class="sub-page-container">
      <div class="sub-header">
        <button @click="$emit('close')" class="back-btn">←</button>
        <h2>공지사항</h2>
      </div>
      
      <div class="sub-content">
        <div v-if="!notices || notices.length === 0" class="no-notice">
          등록된 공지사항이 없습니다.
        </div>

        <div v-for="item in notices" :key="item.id" class="notice-item">
          <div class="notice-header">
            <span class="notice-tag" v-if="item.type">{{ item.type }}</span>
            <span class="notice-date">{{ formatDate(item.createdAt) }}</span>
          </div>
          <h3 class="notice-title" v-if="item.title">{{ item.title }}</h3>
          <p class="notice-text">{{ item.content }}</p>
        </div>
      </div>
    </div>

    <div class="floating-nav-bar">
      <button @click="$emit('close')" class="btn-back-nav">←</button>
      <div class="nav-info-text">전체 공지사항 목록</div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'NoticePage',
  props: {
    notices: {
      type: Array,
      default: () => []
    }
  },
  methods: {
    formatDate(timestamp) {
      if (!timestamp) return '';
      
      let date;
      // Firestore Timestamp 객체 처리
      if (timestamp && typeof timestamp.toDate === 'function') {
        date = timestamp.toDate();
      } else {
        date = new Date(timestamp);
      }

      const y = date.getFullYear();
      const m = String(date.getMonth() + 1).padStart(2, '0');
      const d = String(date.getDate()).padStart(2, '0');
      
      return `${y}.${m}.${d}`;
    }
  }
}
</script>

