<template>
  <div id="app">
    <!-- HW 컴포넌트에 데이터, 저장 함수, 비밀번호 체크 함수를 props로 전달합니다. -->
    <HW 
      v-show="currentView === 'calendar'"
      ref="calendarRef"
      :duty-data="dutyData" 
      :save-duty-entry="saveDutyEntry"
      :check-password="checkPassword"
      @open-qna="currentView = 'qna'"
      @open-notice="currentView = 'notice'"
      @open-setting="currentView = 'setting'"
    />
    <QnaPage v-if="currentView === 'qna'" @close="currentView = 'calendar'" />
    <!-- <NoticePage v-if="currentView === 'notice'" @close="currentView = 'calendar'" /> -->
    <NoticePage v-if="currentView === 'notice'" :notices="noticesData" @close="currentView = 'calendar'" />

    <NewOCCPage v-if="currentView === 'new-occ'"
      :duty-data="dutyData" :save-duty-entry="saveDutyEntry" 
      @close="currentView = 'setting'" @bulk-notified="sendBulkNotification" 
    />

    <SettingPage v-if="currentView === 'setting'" @close="currentView = 'calendar'" @open-new-occ="currentView = 'new-occ'" />

    <div class="floating-nav-bar">
      <div v-if="currentView === 'calendar'" class="nav-item" @click="navPrevMonth">
        <span class="material-icons">chevron_left</span>
        <span class="nav-text">이전달</span>
      </div>

      <div class="nav-item" :class="{ active: currentView === 'notice' }" @click="currentView = 'notice'">
        <span class="material-icons">notifications_active</span>
        <span class="nav-text">공지사항</span>
      </div>

      <div class="nav-item" :class="{ active: currentView === 'calendar' }" @click="goHome">
        <span class="material-icons">event_available</span>
        <span class="nav-text">당직</span>
      </div>

      <div class="nav-item" :class="{ active: currentView === 'qna' }" @click="currentView = 'qna'">
        <span class="material-icons">help_outline</span>
        <span class="nav-text">Q&A</span>
      </div>

      <div v-if="currentView === 'calendar'" class="nav-item" @click="navNextMonth">
        <span class="material-icons">chevron_right</span>
        <span class="nav-text">다음달</span>
      </div>
    </div>
  </div>
</template>

<script>
import HW from './components/HW.vue'
import QnaPage from './components/QNA.vue'
import NoticePage from './components/Notice.vue'
import SettingPage from './components/Setting.vue'
import NewOCCPage from './components/NewOCC.vue'
import { initializeApp } from "firebase/app";
import { getMessaging, getToken, onMessage } from "firebase/messaging";
import { 
  getFirestore, 
  collection, 
  onSnapshot, 
  query, 
  doc, 
  setDoc,
  where,
  getDocs,
  orderBy
} from "firebase/firestore";

import { getFunctions, httpsCallable } from "firebase/functions";

export default {
  name: 'App',
  components: {
    HW, QnaPage, NoticePage, SettingPage, NewOCCPage
  },
  data() {
    return {
      currentView: 'calendar',
      db: null, // Firestore 인스턴스를 저장
      dutyData: [], // Firestore에서 가져온 캘린더 데이터를 저장할 배열
      noticesData: [], // 공지사항 데이터를 담을 배열 추가
      unsubscribe: null, // 실시간 리스너 해제 함수를 저장
      unsubscribeNotices: null // 리스너 해제용 변수 추가
    }
  },
  methods: {
    // 일괄 알림 전송 함수 추가
    async sendBulkNotification(customMessage) {
      try {
        const tokenSnapshot = await getDocs(collection(this.db, "fcm_tokens"));
        const tokens = [];
        tokenSnapshot.forEach((doc) => tokens.push(doc.data().token));
        if (tokens.length === 0) return;

        const functions = getFunctions(undefined, "us-central1"); 
        const sendFcmNotification = httpsCallable(functions, 'sendFcmNotification');

        await sendFcmNotification({
          tokens: tokens,
          title: "📅 당직 업데이트 알림",
          body: customMessage
        });
      } catch (error) {
        console.error("일괄 알림 전송 실패:", error);
      }
    },
    // 캘린더 제어 로직
    goHome() {
      if (this.currentView !== 'calendar') {
        this.currentView = 'calendar';
      } else {
        // 이미 캘린더면 오늘 날짜로 이동
        this.$refs.calendarRef.currentDate = new Date();
      }
    },
    navPrevMonth() {
      this.currentView = 'calendar';
      // HW 컴포넌트 내부의 prevMonth 메서드 실행
      this.$nextTick(() => this.$refs.calendarRef.prevMonth());
    },
    navNextMonth() {
      this.currentView = 'calendar';
      // HW 컴포넌트 내부의 nextMonth 메서드 실행
      this.$nextTick(() => this.$refs.calendarRef.nextMonth());
    },
    // 알림 발송 로직
    async sendAutoNotification(newName, date, oldName) {
      try {
        const tokenSnapshot = await getDocs(collection(this.db, "fcm_tokens"));
        const tokens = [];
        tokenSnapshot.forEach((doc) => tokens.push(doc.data().token));
        if (tokens.length === 0) return;

        const d = String(date);
        const formattedDate = `20${d.substring(0,2)}년 ${d.substring(2,4)}월 ${d.substring(4,6)}일`;
        const messageBody = oldName !== "없음" && oldName !== newName 
          ? `[${formattedDate}] \n당직자가 ${oldName}님 → ${newName}님으로 변경되었습니다.`
          : `[${formattedDate}] \n${newName}님이 당직으로 등록되었습니다.`;

        // 수정된 부분: "us-central1"을 명시해 줍니다.
        const functions = getFunctions(undefined, "us-central1"); 
        const sendFcmNotification = httpsCallable(functions, 'sendFcmNotification');

        const result = await sendFcmNotification({
          tokens: tokens,
          title: "📅 당직 업데이트 알림",
          body: messageBody
        });

        console.log("알림 서버 응답:", result.data);
      } catch (error) {
        console.error("알림 요청 중 오류:", error);
      }
    },

    async saveDutyEntry(entry, docIdToUpdate) {
      if (!this.db) return false;
      
      // const dataToSave = { 
      //   ...entry, 
      //   date: parseInt(entry.date, 10) 
      // };

      // 알림 여부 값을 따로 추출하고, DB 저장 데이터에서는 제외합니다.
      const { sendNotification, ...dataToSave } = entry;
      dataToSave.date = parseInt(entry.date, 10);

      try {
        let oldName = "없음"; // 기존 당직자 이름을 저장할 변수

        // 1. 수정 모드일 때, 기존 데이터에서 이름을 찾아둡니다.
        if (docIdToUpdate) {
          const existingEntry = this.dutyData.find(item => item.id === docIdToUpdate);
          if (existingEntry) {
            oldName = existingEntry.name;
          }
        }

        // 2. 새로운 데이터 저장
        let docRef;
        if (docIdToUpdate) {
          docRef = doc(this.db, "calendar", docIdToUpdate);
        } else {
          docRef = doc(collection(this.db, "calendar"));
        }
        await setDoc(docRef, dataToSave);

        // 3. 알림 함수 호출 시 '이전 이름'과 '새 이름'을 같이 보냅니다.
        // this.sendAutoNotification(dataToSave.name, dataToSave.date, oldName);
        if (sendNotification) {
          this.sendAutoNotification(dataToSave.name, dataToSave.date, oldName);
        } else {
          console.log("알림 전송이 비활성화되어 알림을 보내지 않았습니다.");
        }
        
        return true;
      } catch (error) {
        console.error("저장 에러:", error);
        return false;
      }
    },
    // 비밀번호 검증 함수
    async checkPassword(inputPassword) {
      if (!this.db) {
        console.error("Firestore DB is not initialized.");
        return { success: false, message: "DB 초기화 오류." };
      }
      
      try {
        // 1. password 필드가 입력된 값과 일치하는 문서를 찾는 쿼리 생성
        const passwordQuery = query(
          collection(this.db, "editpw"),
          where("password", "==", inputPassword)
        );

        // 2. 쿼리 실행
        const querySnapshot = await getDocs(passwordQuery);

        // 3. 결과 확인: 일치하는 문서가 1개 이상 존재하면 성공
        if (!querySnapshot.empty) {
          // 일치하는 문서를 찾았습니다. (실제 데이터는 첫 번째 문서의 필드를 사용할 필요 없이 존재 여부만 확인)
          return { success: true };
        } else {
          // 일치하는 문서가 없거나 비밀번호가 틀린 경우
          return { success: false, message: "비밀번호가 일치하지 않습니다." };
        }
      } catch (error) {
        console.error("비밀번호 확인 중 오류 발생:", error);
        return { success: false, message: `비밀번호 확인 중 오류 발생: ${error.message}` };
      }
    },


  },
  mounted() {
  const firebaseConfig = {
    apiKey: "AIzaSyDMjFwCNFE72bctk4BNodId8fLLXMQ_Ulw",
    authDomain: "hello-notification-121eb.firebaseapp.com",
    projectId: "hello-notification-121eb",
    storageBucket: "hello-notification-121eb.firebasestorage.app",
    messagingSenderId: "17313072285",
    appId: "1:17313072285:web:ddbd170a5b062f236fc074",
    measurementId: "G-8W89T2V4CF"
  };

  // 1. Firebase 앱 초기화
  const app = initializeApp(firebaseConfig);
  
  // 2. Firestore 초기화
  this.db = getFirestore(app);

  // 공지사항 실시간 수신 로직 추가
  // notices 컬렉션에서 createdAt 기준으로 내림차순(최신순) 정렬해서 가져오기
  const qNotice = query(collection(this.db, "notice"), orderBy("createdAt", "desc"));
  
  this.unsubscribeNotices = onSnapshot(qNotice, (snapshot) => {
    this.noticesData = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));
    //console.log("공지사항 수신 완료:", this.noticesData); // 데이터가 잘 오는지 확인용
  });
  
  // Messaging 초기화 (getToken 보다 반드시 위에 있어야 함!)
  const messaging = getMessaging(app);

  // 데이터 실시간 수신 설정
  const q = query(collection(this.db, "calendar"), where("date", ">=", 260101), where("date", "<=", 261231));
  this.unsubscribe = onSnapshot(q, (snapshot) => {
    this.dutyData = snapshot.docs.map(doc => ({ 
      id: doc.id, 
      ...doc.data(), 
      date: String(doc.data().date) 
    }));
  });

  // 토큰 가져오기 및 저장 (위에서 만든 messaging 변수를 여기서 사용)
  getToken(messaging, { vapidKey: 'BLYnDWIi8AbuQdrJx1ct6EU5hi6yz6dyG4GxFgLvb_2G42mMjdLwF9i_PkcN8csNR3HynhqVu9ZO92_Am_RcuVg' })
    .then(async (currentToken) => {
      if (currentToken) {
        await setDoc(doc(this.db, "fcm_tokens", currentToken), {
          token: currentToken,
          lastUpdated: new Date()
        }, { merge: true });
        console.log("FCM 토큰 자동 저장 완료");
      }
    }).catch((err) => {
      console.log('토큰 가져오기 실패:', err);
    });

  onMessage(messaging, (payload) => { 
    console.log('메시지 수신:', payload); 
  });
},
  beforeUnmount() {
    // 컴포넌트가 파괴되기 전에 실시간 리스너를 해제합니다.
    if (this.unsubscribe) this.unsubscribe();
    if (this.unsubscribeNotices) this.unsubscribeNotices();
  }
}
</script>

